INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, -416.5, "2030/01/01 14:59:59", 1, 190805, 1, 3.414, "カリン", "2025/01/31 12:00:00", 2, 62, 0.0, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 1000001);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, -416.5, "2030/01/01 14:59:59", 2, 190805, 1, 3.099, "カリン", "2025/01/31 12:00:00", 2, 62, 0.0, "ミッションをクリアして、\n報酬をゲットしましょう！", 1000002);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, -416.5, "2030/01/01 14:59:59", 3, 190805, 1, 2.801, "カリン", "2025/01/31 12:00:00", 2, 63, 0.0, "受け取ることができる\n報酬があるようです\n確認してみてください", 1000003);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, -416.5, "2030/01/01 14:59:59", 4, 190805, 2, 0.0, "カリン", "2025/01/31 12:00:00", 2, 63, 0.0, "報酬がもらえますよ！\nチェックしてみてください", 1000004);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, -363.0, "2030/01/01 14:59:59", 5, 190805, 2, 2.12, "カリン", "2025/01/31 12:00:00", 1, 64, 0.0, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 1000005);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, -363.0, "2030/01/01 14:59:59", 6, 190805, 1, 1.68, "カリン", "2025/01/31 12:00:00", 2, 64, 0.0, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 1000006);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (1, -363.0, "2030/01/01 14:59:59", 7, 190805, 2, 2.33, "カリン", "2025/01/31 12:00:00", 1, 64, 0.0, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 1000007);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10201, -285.0, "2030/01/01 14:59:59", 101, 133701, 3, 5.18, "ラビリスタ", "2025/01/31 12:00:00", 7, 61, -6.0, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", 1020101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10201, -285.0, "2030/01/01 14:59:59", 201, 133901, 1, 8.77, "クリスティーナ", "2025/01/31 12:00:00", 2, 61, -2.0, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", 1020102);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10201, -285.0, "2030/01/01 14:59:59", 301, 133801, 6, 15.5, "ネネカ", "2025/01/31 12:00:00", 1, 61, 0.0, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", 1020103);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10202, -285.0, "2030/01/01 14:59:59", 101, 134301, 2, 9.061, "ランファ", "2025/02/28 12:00:00", 5, 61, 0.0, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", 1020201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10202, -285.0, "2030/01/01 14:59:59", 201, 134401, 1, 7.699, "チカ", "2025/02/28 12:00:00", 2, 61, 0.0, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", 1020202);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10203, -285.0, "2030/01/01 14:59:59", 101, 134601, 1, 8.595, "アオイ", "2025/03/31 12:00:00", 2, 61, 0.0, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", 1020301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10203, -285.0, "2030/01/01 14:59:59", 201, 134501, 1, 7.758, "クローチェ", "2025/03/31 12:00:00", 2, 61, 0.0, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", 1020302);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10204, -285.0, "2030/01/01 14:59:59", 101, 132302, 2, 7.0, "ルイズマリー", "2025/04/30 12:00:00", 6, 61, 0.0, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", 1020401);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10204, -285.0, "2030/01/01 14:59:59", 201, 132402, 1, 7.904, "イロハ", "2025/04/30 12:00:00", 2, 61, 0.0, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", 1020402);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10204, -285.0, "2030/01/01 14:59:59", 301, 132502, 4, 8.487, "ソノ", "2025/04/30 12:00:00", 2, 61, 0.0, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", 1020403);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10205, -285.0, "2030/01/01 14:59:59", 101, 134901, 1, 8.763, "カノン", "2025/05/31 12:00:00", 2, 61, 0.0, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", 1020502);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10205, -285.0, "2030/01/01 14:59:59", 201, 134801, 1, 6.417, "ツムギ", "2025/05/31 12:00:00", 3, 61, 0.0, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", 1020503);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10206, -285.0, "2030/01/01 14:59:59", 101, 135001, 3, 10.335, "エリス", "2025/06/30 12:00:00", 7, 61, 0.0, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", 1020601);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10206, -285.0, "2030/01/01 14:59:59", 201, 135101, 2, 6.281, "シェフィ", "2025/06/30 12:00:00", 4, 61, 0.0, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", 1020602);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10206, -285.0, "2030/01/01 14:59:59", 301, 135201, 1, 12.244, "プレシア", "2025/06/30 12:00:00", 2, 61, 0.0, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", 1020603);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10207, -285.0, "2030/01/01 14:59:59", 101, 135301, 2, 6.339, "クリア", "2025/07/31 12:00:00", 8, 61, 0.0, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", 1020701);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10207, -285.0, "2030/01/01 14:59:59", 201, 135401, 7, 8.184, "アネモネ", "2025/07/31 12:00:00", 9, 61, 0.0, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", 1020702);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10208, -285.0, "2030/01/01 14:59:59", 101, 129101, 9, 3.906, "アイラ", "2025/08/31 12:00:00", 2, 61, 0.0, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", 1020801);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10208, -285.0, "2030/01/01 14:59:59", 201, 129201, 1, 14.465, "シナツ", "2025/08/31 12:00:00", 2, 61, 0.0, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", 1020802);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10208, -285.0, "2030/01/01 14:59:59", 301, 100101, 4, 8.662, "ヒヨリ", "2025/08/31 12:00:00", 3, 61, 0.0, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", 1020803);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10208, -285.0, "2030/01/01 14:59:59", 401, 100301, 1, 10.915, "レイ", "2025/08/31 12:00:00", 3, 61, 0.0, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", 1020804);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10209, -285.0, "2030/01/01 14:59:59", 101, 135802, 1, 6.042, "ユキノ", "2025/09/30 12:00:00", 7, 61, 0.0, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", 1020901);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10209, -285.0, "2030/01/01 14:59:59", 201, 135903, 4, 9.402, "サツキ", "2025/09/30 12:00:00", 1, 61, 0.0, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", 1020902);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10209, -285.0, "2030/01/01 14:59:59", 301, 136902, 8, 8.16, "ルルィ", "2025/09/30 12:00:00", 1, 61, 0.0, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", 1020903);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10210, -285.0, "2030/01/01 14:59:59", 101, 137401, 3, 5.0, "カスミ", "2025/10/31 12:00:00", 2, 61, 0.0, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", 1021001);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10210, -285.0, "2030/01/01 14:59:59", 201, 136001, 4, 8.12, "アラクネ", "2025/10/31 12:00:00", 1, 61, 0.0, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", 1021002);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10210, -285.0, "2030/01/01 14:59:59", 301, 136202, 4, 6.386, "ナーナ", "2025/10/31 12:00:00", 2, 61, 0.0, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", 1021003);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10211, -285.0, "2030/01/01 14:59:59", 101, 136402, 3, 7.438, "ユイ", "2025/11/30 12:00:00", 4, 61, 0.0, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", 1021101);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10211, -285.0, "2030/01/01 14:59:59", 201, 136302, 1, 8.35, "ミソラ", "2025/11/30 12:00:00", 5, 61, 0.0, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", 1021102);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10212, -285.0, "2030/01/01 14:59:59", 101, 136501, 1, 5.0, "シズル", "2025/12/31 12:00:00", 2, 61, 0.0, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", 1021201);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10212, -285.0, "2030/01/01 14:59:59", 201, 137902, 1, 5.25, "リノ", "2025/12/31 12:00:00", 2, 61, 0.0, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", 1021202);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10212, -285.0, "2030/01/01 14:59:59", 301, 106801, 1, 7.5, "ラビリスタ", "2025/12/31 12:00:00", 2, 61, 0.0, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", 1021203);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10213, -285.0, "2030/01/01 14:59:59", 101, 126501, 1, 8.204, "ライラエル", "2026/01/31 12:00:00", 2, 61, 0.0, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", 1021301);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10213, -285.0, "2030/01/01 14:59:59", 201, 129701, 1, 7.176, "ネフィ＝ネラ", "2026/01/31 12:00:00", 2, 61, 0.0, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", 1021302);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10213, -285.0, "2030/01/01 14:59:59", 301, 133101, 1, 8.602, "ヴァイオレット", "2026/01/31 12:00:00", 5, 61, 0.0, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", 1021303);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10213, -285.0, "2030/01/01 14:59:59", 102, 138101, 1, 10.14, "ライラエル", "2026/02/06 12:00:00", 3, 61, 0.0, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", 1021304);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10213, -285.0, "2030/01/01 14:59:59", 202, 138201, 1, 10.152, "ネフィ＝ネラ", "2026/02/06 12:00:00", 7, 61, 0.0, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", 1021305);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10213, -285.0, "2030/01/01 14:59:59", 302, 138001, 4, 9.688, "ヴァイオレット", "2026/02/06 12:00:00", 3, 61, 0.0, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", 1021306);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10213, -285.0, "2030/01/01 14:59:59", 401, 138301, 2, 5.928, "ペコリーヌ", "2026/02/12 12:00:00", 1, 61, 0.0, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", 1021307);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10214, -285.0, "2030/01/01 14:59:59", 101, 138702, 4, 9.19, "ワカナ", "2026/02/28 12:00:00", 2, 61, 0.0, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", 1021401);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES (10214, -285.0, "2030/01/01 14:59:59", 201, 138802, 1, 8.724, "シオリ", "2026/02/28 12:00:00", 3, 61, 0.0, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", 1021402);
